// Parse incoming WhatsApp message
// Compatible with WhatsApp Business API / Respond.io / Twilio format
const body = $input.all()[0].json.body || $input.all()[0].json;

// Extract message based on provider format
let message, phone, name, sessionId;

// WhatsApp Business API (Meta Cloud API) format
if (body.entry && body.entry[0]) {
  const changes = body.entry[0].changes[0];
  const msg = changes.value.messages[0];
  message = msg.text?.body || '';
  phone = msg.from;
  name = changes.value.contacts?.[0]?.profile?.name || 'Customer';
  sessionId = phone;
}
// Respond.io format
else if (body.contact && body.message) {
  message = body.message.text || body.message.body || '';
  phone = body.contact.phone || body.contact.id;
  name = body.contact.name || 'Customer';
  sessionId = body.contact.id;
}
// Twilio format
else if (body.Body && body.From) {
  message = body.Body;
  phone = body.From.replace('whatsapp:', '');
  name = body.ProfileName || 'Customer';
  sessionId = phone;
}
// Generic fallback
else {
  message = body.message || body.text || '';
  phone = body.phone || body.from || '';
  name = body.name || 'Customer';
  sessionId = phone || 'unknown';
}

return [{
  json: {
    message,
    phone,
    name,
    sessionId,
    timestamp: new Date().toISOString()
  }
}];

// Format response for WhatsApp reply
const aiResponse = $input.all()[0].json;
let replyText = '';

// Handle different response formats
if (typeof aiResponse === 'string') {
  replyText = aiResponse;
} else if (aiResponse.output) {
  replyText = aiResponse.output;
} else if (aiResponse.text) {
  replyText = aiResponse.text;
} else if (aiResponse.data) {
  replyText = aiResponse.data;
} else {
  replyText = JSON.stringify(aiResponse);
}

// Clean up any lead capture tags from the response
replyText = replyText.replace(/\[LEAD_CAPTURED\].*?\[\/LEAD_CAPTURED\]/gs, '').trim();

// Get original message context
const phone = $('Parse WhatsApp Message').item.json.phone;
const name = $('Parse WhatsApp Message').item.json.name;

return [{
  json: {
    phone,
    name,
    reply: replyText
  }
}];
